import React, { lazy, Suspense } from 'react'

const RelationshipViewerButton = lazy(() => import('@fs/zion-relationship-viewer'))

export default function ViewRelationshipAllOptedInView({ contact, relationshipData, relationshipDescription }) {
  const id = contact?.cisId || contact?.cpUserId
  const idType = (contact?.cisId && 'cisId') || contact?.cpUserId || 'contributorId'
  return (
    <>
      {id && (
        <Suspense fallback="">
          <RelationshipViewerButton
            toId={id}
            relationshipIdType={idType}
            relationshipData={relationshipData}
            customText={relationshipDescription}
            asListItem
          />
        </Suspense>
      )}
    </>
  )
}
